const raw = $input.first().json.body || $input.first().json;
const getFirst = (...names) => {
  for (const n of names) {
    const v = n.split('.').reduce((acc,k) => (acc && acc[k] !== undefined) ? acc[k] : undefined, raw);
    if (v !== undefined && v !== null && v !== '') return v;
  }
  return '';
};
const callId = getFirst('call_id','execution_id','id','context_details.call_id');
const startedAt = getFirst('started_at','call_started_at','conversation_started_at');
const endedAt = getFirst('ended_at','call_ended_at','conversation_ended_at');
const callerNumber = getFirst('from_number','caller_number','customer_number','context_details.from_number');
const transcript = (() => {
  const t = getFirst('transcript','conversation','messages');
  if (Array.isArray(t)) return t.map(m => `${m.role||''}: ${m.content||m.text||''}`).join('\n');
  return String(t||'');
})();
const recording = getFirst('recording_url','telephony_data.recording_url','call_recording');
return [{ json: {
  call_id: String(callId||''),
  started_at: String(startedAt||''),
  ended_at: String(endedAt||''),
  caller_number: String(callerNumber||''),
  transcript,
  recording_url: String(recording||''),
  raw_payload_json: JSON.stringify(raw),
  sheet_id: '1xvbM37zAPLflfjLn66tWv0jGiFpSrrBILM-drdW0Da0'
}}];

const n = $('Normalise payload').item.json;
const data = $input.first().json;
const rows = data.values || [];
const header = rows[0] || [];
const idx = {};
header.forEach((h,i) => { idx[h] = i; });
const match = rows.slice(1).find(r => r[idx['call_id']] === n.call_id);
let booking = {};
if (match) {
  booking = {
    calendar_event_id: match[idx['calendar_event_id']] || '',
    appointment_time: match[idx['start_iso']] || '',
    service: match[idx['service']] || '',
    caller_name: match[idx['patient_name']] || '',
    appointment_booked: true
  };
}
return [{ json: Object.assign({}, n, booking) }];

const item = $input.first().json;
let text = (item.message && item.message.content) ? item.message.content : (item.output || item.text || item.content || '');
if (typeof text !== 'string') text = JSON.stringify(text);
let parsed = {};
try { parsed = JSON.parse(text); } catch(_) {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch(_) {} }
}
const merged = $('Merge booking info').item.json;
return [{ json: Object.assign({}, merged, {
  summary: parsed.summary || '',
  intent: parsed.intent || (merged.appointment_booked ? 'booking' : 'other'),
  sentiment: parsed.sentiment || 'neutral',
  follow_up_needed: !!parsed.follow_up_needed,
  follow_up_reason: parsed.follow_up_reason || ''
})}];
